mapper.insert:
INSERT IGNORE INTO support_session (
    member_id, status, sort_time
) VALUES (
    #{memberId}, 'OPEN', CURRENT_TIMESTAMP
)

mapper.update:
UPDATE support_session
SET member_unread_count = 0
WHERE id = #{id}

UPDATE support_session
SET admin_unread_count = 0
WHERE id = #{id}

mapper.select:
SELECT 
FROM support_session ss
INNER JOIN member_user u ON u.id = ss.member_id
WHERE 1 = 1

    AND ss.status = #{status}


    AND (
        u.username LIKE CONCAT(#{keyword}, '%')
        OR u.mail LIKE CONCAT(#{keyword}, '%')
    )


    AND (
        ss.sort_time < #{cursorCreatedAt}
        OR (ss.sort_time = #{cursorCreatedAt} AND ss.id < #{cursorId})
    )

ORDER BY ss.sort_time DESC, ss.id DESC
LIMIT #{limit}

SELECT 
FROM support_session ss
INNER JOIN member_user u ON u.id = ss.member_id
WHERE ss.updated_at > #{updatedAfter}

    AND ss.status = #{status}


    AND (
        u.username LIKE CONCAT(#{keyword}, '%')
        OR u.mail LIKE CONCAT(#{keyword}, '%')
    )

ORDER BY ss.updated_at ASC, ss.id ASC
LIMIT #{limit}
